const html = $input.first().json.data;
const appliedUrls = new Set($('Load Log + Record Session Start').first().json.appliedUrls);
const MAX = parseInt($env.HH_MAX_PER_SESSION || '5');
const matches = [...html.matchAll(/href="(\/vacancy\/(\d+)[^"]*)"/g)];
const seen = new Set(); const result = [];
for (const m of matches) {
  const url = 'https://hh.ru' + m[1]; const id = m[2];
  if (seen.has(id) || appliedUrls.has(url) || result.length >= MAX) continue;
  seen.add(id);
  const snip = html.slice(m.index, m.index + 400);
  const tM = snip.match(/data-qa="serp-item__title"[^>]*>([^<]+)</);
  const cM = snip.match(/data-qa="vacancy-serp__vacancy-employer"[^>]*>([^<]+)</);
  result.push({ url, vacancy_id: id, title: tM?.[1]?.trim() ?? `Vacancy ${id}`, company: cM?.[1]?.trim() ?? '', index: result.length + 1 });
}
console.log(`Candidates after dedup: ${result.length}`);
return result.map(v => ({ json: v }));

const STOP = ['gambling','казино','casino','ставки','букмекер','adult','dating','знакомств','forex','трейдинг','нфт','nft','млм','mlm','микрозайм','мфо','junior','джуниор'];
const fs = require('fs');
const LOG_PATH = '/Users/kashitcyn/.openclaw/workspace/HH_Auto/applied_log.json';
const now = new Date().toISOString();
const passed = [], stopped = [];
for (const item of $input.all()) {
  const t = (item.json.title + ' ' + item.json.company).toLowerCase();
  const hit = STOP.find(w => t.includes(w));
  if (hit) stopped.push({ ...item.json, status: 'skipped_stop_word', reason: `stop_word:${hit}`, date: now, score: null, cover_letter: false, scenario: 'pre_filter' });
  else passed.push(item.json);
}
if (stopped.length) {
  let log = []; try { log = JSON.parse(fs.readFileSync(LOG_PATH, 'utf8')); } catch(e) {}
  log.push(...stopped);
  fs.writeFileSync(LOG_PATH, JSON.stringify(log, null, 2), 'utf8');
}
console.log(`Passed: ${passed.length}, Stopped: ${stopped.length}`);
return passed.map(v => ({ json: v }));

