const fs = require('fs');
const LOG_PATH = '/Users/kashitcyn/.openclaw/workspace/HH_Auto/applied_log.json';
let log = []; try { log = JSON.parse(fs.readFileSync(LOG_PATH,'utf8')); } catch(e) {}
const item = $input.first().json;
const vacUrl = item.chat_url || item.vacancy_url || '';
const idx = log.findIndex(e => e.url && vacUrl.includes(e.url.split('/').pop()?.split('?')[0]));
const update = { chat_checked: new Date().toISOString(), chat_summary: item.msg_summary||'', last_msg_type: item.msg_type||'other' };
if (item.msg_type==='interview_invite') { update.interview_invited=true; update.interview_details=item.interview_details||''; update.status_chat='invited'; }
if (item.msg_type==='rejection') update.status_chat='rejected';
if (item.msg_type==='question') update.status_chat='replied';
if (idx>=0) log[idx]={...log[idx],...update};
else log.push({url:item.chat_url||'',title:item.vacancy_title||'',date:new Date().toISOString(),...update});
fs.writeFileSync(LOG_PATH, JSON.stringify(log,null,2),'utf8');
return [{ json: { updated:true, type:item.msg_type, title:item.vacancy_title } }];

