const fs = require('fs');
const LOG_PATH = '/Users/kashitcyn/.openclaw/workspace/HH_Auto/applied_log.json';
const STATE_PATH = '/tmp/hh_session_state.json';
let log = [], state = { baseline_count: 0 };
try { log = JSON.parse(fs.readFileSync(LOG_PATH,'utf8')); } catch(e) {}
try { state = JSON.parse(fs.readFileSync(STATE_PATH,'utf8')); } catch(e) {}
const session = log.slice(state.baseline_count);
const errors = session.filter(e =>
  e.status?.includes('skipped_error') ||
  e.status?.includes('skipped_hh_modal') ||
  e.status?.includes('skipped_no') ||
