);
const applied = session.filter(e => e.status?.startsWith('applied')).length;
console.log(`Session total: ${session.length}, errors: ${errors.length}, applied: ${applied}`);
return [{ json: { total_errors: errors.length, total_applied: applied, session_total: session.length, error_breakdown: errors.reduce((a,e)=>{a[e.status]=(a[e.status]||0)+1;return a},{}), baseline_count: state.baseline_count } }];

