const fs = require('fs'), path = require('path');
const DIR = '/Users/kashitcyn/hh-auto-test/snapshots';
let folders = [];
try { folders = fs.readdirSync(DIR).filter(f => fs.statSync(path.join(DIR,f)).isDirectory()).sort().reverse(); } catch(e) {}
if (!folders.length) return [{ json: { error: 'no snapshots', data_qa: [], modal_html_preview: '' } }];
const latest = path.join(DIR, folders[0]);
let data_qa = [], modal_html = '';
try { data_qa = fs.readFileSync(path.join(latest,'data_qa.txt'),'utf8').split('\n').filter(Boolean); } catch(e) {}
try { modal_html = fs.readFileSync(path.join(latest,'modal.html'),'utf8').slice(0,6000); } catch(e) {}
return [{ json: { snapshot_folder: folders[0], data_qa, modal_html_preview: modal_html } }];

const snap = $('Read Inspector Snapshot').item.json;
