const emoji = a.severity==='critical'?'🚨':a.severity==='warning'?'⚠️':'ℹ️';
const tg = `${emoji} *HH Debug Report*

*Errors this session:* ${errData.total_errors}
*Severity:* ${a.severity}

*Diagnosis:*
${a.diagnosis}

*Fix:*
${a.suggested_fix}

*Missing:* ${(a.missing_selectors||[]).join(', ')||'none'}
*New:* ${(a.new_selectors||[]).join(', ')||'none'}`;
return [{ json: { tg_text: tg, severity: a.severity, report } }];

const fs = require('fs');
const LOG_PATH = '/Users/kashitcyn/.openclaw/workspace/HH_Auto/applied_log.json';
const PROFILE_PATH = '/Users/kashitcyn/.openclaw/workspace/HH_Auto/market_profile.json';
let log = []; try { log = JSON.parse(fs.readFileSync(LOG_PATH,'utf8')); } catch(e) {}
const sigFreq = {}, statusFreq = {};
const scores = log.filter(e => e.score != null).map(e => e.score);
const invited = log.filter(e => e.interview_invited);
for (const e of log) {
  for (const s of (e.signals||[])) sigFreq[s]=(sigFreq[s]||0)+1;
  const st=e.status||'unknown'; statusFreq[st]=(statusFreq[st]||0)+1;
}
const avg = n => n.length ? Math.round(n.reduce((a,b)=>a+b,0)/n.length) : null;
const profile = { last_updated: new Date().toISOString(), total_analyzed: log.length, status_breakdown: statusFreq, signal_frequency: Object.fromEntries(Object.entries(sigFreq).sort((a,b)=>b[1]-a[1])), avg_score_all: avg(scores), avg_score_applied: avg(log.filter(e=>e.score!=null&&e.status?.startsWith('applied')).map(e=>e.score)), interview_invite_rate: log.length?`${((invited.length/log.length)*100).toFixed(1)}%`:'0%', interviews: invited.map(e=>({title:e.title,url:e.url,score:e.score,date:e.date})) };
fs.writeFileSync(PROFILE_PATH, JSON.stringify(profile,null,2),'utf8');
console.log('Session complete. Market profile updated.');
return [{ json: profile }];
